#include "event_parser.h"
#include <assert.h>
static void feed(event_parser_t *p, const uint8_t *b, size_t n, event_result_t want, size_t len){ const uint8_t *out; size_t got=99; event_result_t r=EVENT_NEED_MORE; for(size_t i=0;i<n;i++) r=event_parser_feed(p,b[i],&out,&got); assert(r==want); if(want==EVENT_FRAME_READY) assert(got==len); }
int main(void){ event_parser_t p; event_parser_init(&p); uint8_t v[]={EVENT_START_BYTE,1,2,EVENT_END_BYTE}; feed(&p,v,4,EVENT_FRAME_READY,2); uint8_t e[]={EVENT_START_BYTE,EVENT_END_BYTE}; feed(&p,e,2,EVENT_FRAME_READY,0); uint8_t inc[]={EVENT_START_BYTE,1}; feed(&p,inc,2,EVENT_NEED_MORE,0); event_parser_init(&p); uint8_t big[40]; big[0]=EVENT_START_BYTE; for(size_t i=1;i<39;i++) big[i]=(uint8_t)i; big[39]=EVENT_END_BYTE; feed(&p,big,40,EVENT_REJECTED,0); uint8_t rec[]={9,EVENT_START_BYTE,3,EVENT_END_BYTE,EVENT_START_BYTE,4,EVENT_END_BYTE}; feed(&p,rec,7,EVENT_FRAME_READY,1); event_parser_init(&p); assert(p.state==EVENT_WAIT_START); return 0; }
